create table dirkspzm32.meldung_zuordnung (
    guid                 varchar2(64 char) default sys_guid() not null enable,
    mt_index             number(6, 2) not null enable,
    mt_gruppe            number(3, 0) not null enable,
    mt_fehlernr          number(5, 0),
    mt_sprache           number(*, 5) not null enable,
    mht_guid             varchar2(64 char) not null enable,
    pos                  number(*, 0) not null enable,
    mt_fehlernr_str      varchar2(8 char),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.meldung_zuordnung
    add constraint pk_meldung_zuordnung primary key ( guid )
        using index enable;


